frontend_dir = "d:/Saeed Furniture/frontend"
html_files = glob.glob(os.path.join(frontend_dir, "*.html"))

for file_path in html_files:
    with open(file_path, "r", encoding="utf-8") as f:
        content = f.read()

    # Apply all dictionary replacements
    for mojibake, arabic in replacements.items():
        content = content.replace(mojibake, arabic)

    # Specific fix for about.html hero image
    if os.path.basename(file_path) == "about.html":
        content = content.replace("url('/images/heritage_floor.png')", "url('/images/trust_handshake.png')")
        # Ensure about page uses hero-bg styling correctly if needed
        # The prompt mentioned "change the image in the background. generate one with two people shaking hands with their head not in the view"
        # The background was applied inline or via a class. Let's make sure /images/trust_handshake.png is set.
        content = content.replace("/images/heritage_floor.png", "/images/trust_handshake.png")

    with open(file_path, "w", encoding="utf-8") as f:
        f.write(content)

